#include <bits/stdc++.h>
using namespace std;
const int N=3e3+5;
int n,a[N],b[N],dp[N][N];
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1;i<=n;i++)
		scanf("%d",&b[i]);
	a[0]=b[0]=-((1LL<<31)-1);
	for(int i=1;i<=n;i++){
		int mx=0;
		for(int j=1;j<=n;j++){
			if(a[i]==b[j])
				dp[i][j]=mx+1;
			else
				dp[i][j]=dp[i-1][j];
			if(b[j]<a[i])
				mx=max(mx,dp[i-1][j]);
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++)
		ans=max(ans,dp[n][i]);
	printf("%d",ans);
	return 0;
}
